// Refresh-token issuance: store only the hash of an opaque secret
const raw = randomBytes(64).toString('hex');
const tokenHash = createHash('sha256').update(raw).digest('hex');
await this.prisma.refreshToken.create({
  data: {
    user_id: userId,
    token_hash: tokenHash,
    expires_at: addDays(new Date(), REFRESH_TOKEN_TTL_DAYS),
  },
});
return { refreshToken: raw }; // the raw secret is returned once, never stored

// Activation is gated by the readiness check
if (nextStatus === LabOnboardingStatus.Active) {
  const readiness = buildOnboardingReadiness(lab);
  if (!readiness.isReady) {
    throw new BadRequestException(
      `Lab is not ready to activate. Missing: ${readiness.missing.join(', ')}`,
    );
  }
}
await this.prisma.labProfile.update({
  where: { id: labProfileId },
  data: { onboarding_status: nextStatus },
});

// A test cannot be deleted while bookings depend on it
const bookingCount = await this.prisma.booking.count({
  where: { lab_test_id: testId },
});
if (bookingCount > 0) {
  throw new BadRequestException(
    'Cannot delete a test that has existing bookings.',
  );
}
await this.prisma.labTest.delete({ where: { id: testId } });

// Atomic booking creation guards against slot double-booking
try {
  return await this.prisma.$transaction(async (tx) => {
    const booking = await tx.booking.create({ data: { /* order */
      status: BookingStatus.Pending,
      payment_status: PaymentStatus.Pending, schedule_slot_id: slotId } });
    await tx.bookingStatusEvent.create({ data: { booking_id: booking.id,
      status: BookingStatus.Pending, note: 'Booking created by patient' } });
    return booking;
  });
} catch (e) {
  if (isUniqueViolation(e)) // P2002 on the unique schedule_slot_id
    throw new ConflictException('Selected slot is already booked');
  throw e;
}

// Defence-in-depth PDF validation: MIME type AND magic bytes
const isPdfMime = file.mimetype === 'application/pdf';
const hasPdfMagic =
  file.buffer.subarray(0, 4).toString('latin1') === '%PDF';
if (!isPdfMime || !hasPdfMagic) {
  throw new BadRequestException('Only PDF result files are accepted.');
}
const stored = await this.storage.persist(file); // local disk or S3

// Recompute denormalised rating from published reviews
const agg = await tx.review.aggregate({
  where: { lab_profile_id: labId, status: ReviewStatus.Published },
  _avg: { rating: true },
  _count: { _all: true },
});
await tx.labProfile.update({
  where: { id: labId },
  data: {
    rating_average: agg._avg.rating ?? null,
    review_count: agg._count._all,
  },
});

for (let round = 0; round < MAX_TOOL_ROUNDS; round++) {
  const stream = await client.models.generateContentStream({
    model: MODEL, contents,
    config: { systemInstruction: SYSTEM_PROMPT, tools: TOOLS } });
  const calls = [];
  for await (const chunk of stream) {
    if (chunk.text) onEvent({ type: 'delta', text: chunk.text });
    for (const fc of chunk.functionCalls ?? []) calls.push(fc);
  }
  if (calls.length === 0) break;            // final answer
  for (const call of calls) {
    const { result } = await this.runTool(call);
    if (result) onEvent({ type: 'tool', result }); // card to UI
  }
}

// Deterministic keyword/tag match — no model involved
const where: Prisma.FaqEntryWhereInput = { is_active: true };
if (q) {
  const words = q.split(/\s+/).filter((w) => w.length > 1);
  where.OR = [
    { question: { contains: q, mode: 'insensitive' } },
    { answer: { contains: q, mode: 'insensitive' } },
    { tags: { hasSome: words } },
  ];
}
return this.prisma.faqEntry.findMany({ where, orderBy: { updated_at: 'desc' } });

// Privacy scoping applied at the database level
const fullHistory =
  patient.lab_history_sharing === LabHistorySharing.FULL_HISTORY_AUTHORIZED;
const where: Prisma.BookingWhereInput = fullHistory
  ? { patient_profile_id: patient.id }            // all labs
  : { patient_profile_id: patient.id,             // this lab only
      lab_profile_id: labProfile.id };
// PDF links are emitted only for this lab's own uploads, never others'.
